const pollMs = 100;
const arrowNames = new Set(['arrow', 'spectral_arrow', 'tipped_arrow']);
const hostileNames = new Set(['zombie', 'skeleton', 'husk', 'drowned', 'stray', 'spider', 'creeper', 'enderman', 'witch', 'piglin', 'ravager', 'vindicator', 'evoker', 'zoglin']);

const findNearestHostile = function() {
  return Object.values(bot.entities).find(function(e) {
    if (!e || !e.isValid || e.type !== 'hostile' && !hostileNames.has(e.name)) return false;
    if (e.position.distanceTo(bot.entity.position) > 40) return false;
    if (args.targetEntityId && String(e.id) !== String(args.targetEntityId)) return false;
    return true;
  });
};

const getArrowCount = function() {
  return bot.inventory.items().filter(function(i) { return arrowNames.has(i.name); }).reduce(function(acc, i) { return acc + i.count; }, 0);
};

if (!bot.entity || bot.health <= 0) {
  return '<UNSAFE>: Bot is dead or missing.';
}

let bowItem = null;
if (args.equipBow) {
  bowItem = bot.inventory.items().find(function(i) { return i.name === 'bow'; });
  if (!bowItem) {
    return '<NO ITEM>: Bow requested for kiting but not found in inventory.';
  }
  if (getArrowCount() <= 0) {
    return '<NO ITEM>: Bow requested but no arrows found.';
  }
}

const initialTarget = findNearestHostile();
if (!initialTarget) {
  return '<NO TARGET>: No hostiles nearby to kite.';
}

startBackgroundSkill(bot, 'kite_nearest_hostile', async function(token) {
  const movements = new Movements(bot);
  movements.canDig = false;
  bot.pathfinder.setMovements(movements);

  let lastShotAt = 0;
  const startTime = Date.now();

  try {
    while (canContinueBotAction(bot, token) && (Date.now() - startTime) < args.maxDurationMs) {
      const target = findNearestHostile();
      if (!target) break;

      const dist = bot.entity.position.distanceTo(target.position);

      if (dist < args.retreatThreshold) {
        const direction = bot.entity.position.minus(target.position).normalize();
        const retreatPos = target.position.plus(direction.scaled(args.preferredDistance));
        bot.pathfinder.setGoal(new goals.GoalNear(retreatPos.x, retreatPos.y, retreatPos.z, 2));
      } else if (dist > args.preferredDistance + 5) {
        bot.pathfinder.setGoal(new goals.GoalFollow(target, args.preferredDistance));
      } else {
        bot.pathfinder.setGoal(null);
      }

      if (args.equipBow && bowItem && getArrowCount() > 0) {
        const now = Date.now();
        if (now - lastShotAt > 2000) {
          await bot.equip(bowItem, 'hand');
          const aimPos = target.position.offset(0, target.height * 0.8, 0);
          await bot.lookAt(aimPos, true);
          bot.activateItem();
          if (await waitForActiveMs(bot, token, 1000, 50)) {
            bot.deactivateItem();
            lastShotAt = Date.now();
          }
        }
      }

      if (!await waitForActiveMs(bot, token, pollMs, 50)) break;
    }
  } finally {
    bot.pathfinder.setGoal(null);
    bot.deactivateItem();
    bot.clearControlStates();
  }
});

return '<STARTED>: Kiting hostiles, maintaining distance of ' + args.preferredDistance + ' blocks.';
